    rm_orders: { t: "Замовлення", b: ["Замовлення згруповані за днями; день розкривається кліком і лише тоді тягне деталі.", "Пошук шукає за номером, email, телефоном і вмістом кошика, а списки згори фільтрують за статусом."] },
    rm_clients: { t: "Клієнти", b: ["Клієнт з’являється сам — під час першого замовлення чи входу в кабінет; заводити руками не треба.", "Фільтри згори звужують список за статусом і типом, а пошук дивиться й у контакти."] },
    rm_appointments: { t: "Записи", b: ["Три вигляди одного й того самого: дерево записів, розклад-стрічка і 3D-куб зайнятості.", "Клієнт може сам перенести чи скасувати свій запис із кабінету — якщо встигає до межі, заданої в позиції Каталогу."] },
    rm_company: { t: "Загальні налаштування", b: ["Структура компанії, ключі інтеграцій і Довідка П/ПФФ із таблицями можливостей.", "Ці дані читає і сайт, і листи клієнтам — тому тримайте їх в актуальному стані."] },
